70	__device__ inline float4 add_float4(const float4& a, const float4& b) {
71	    return make_float4(a.x + b.x, a.y + b.y, a.z + b.z, a.w + b.w);
72	}
73	
74	// use of float4 leads to using 128-bit LDG / STG instructions in SASS,
75	// very helpful in memory-bound kernels like encoder_forward
76	__global__ void encoder_forward_kernel3(float4* out,
77	                               const int* inp, const float4* wte, const float4* wpe,
78	                               int B, int T, int C) {
79	    int C4 = C / 4;
80	    int idx = blockIdx.x * blockDim.x + threadIdx.x;
81	    int N = B * T * C4;
82	    if (idx < N) {
83	        int bt = idx / C4;
84	        int b = bt / T;
85	        int t = bt % T;
86	        int c4 = idx % C4;
87	        int ix = inp[b * T + t];
88	        out[b * T * C4 + t * C4 + c4] = add_float4(wte[ix * C4 + c4], wpe[t * C4 + c4]);
89	    }
90	}
