92	// really bad naive kernel with atomicAdd
93	__global__ void encoder_backward_kernel(float* dwte, float* dwpe,
94	                                        const float* dout, const int* inp,
95	                                        int B, int T, int C) {
96	    int idx = blockIdx.x * blockDim.x + threadIdx.x;
97	    int N = B * T * C;
98	
99	    if (idx < N) {
100	        int bt = idx / C;
101	        int b = bt / T;
102	        int t = bt % T;
103	        int c = idx % C;
104	
105	        int ix = inp[b * T + t];
106	
107	        const float* dout_btc = dout + b * T * C + t * C + c;
108	        float* dwte_ix = dwte + ix * C + c;
109	        float* dwpe_tc = dwpe + t * C + c;
110	
111	        atomicAdd(dwte_ix, *dout_btc);
112	        atomicAdd(dwpe_tc, *dout_btc);
113	    }
114	}
