116	__global__ void layernorm_forward_kernel3(float* __restrict__ out, float* __restrict__ mean, float* __restrict__ rstd,
117	                                    const float*  __restrict__ inp, const float*  __restrict__ weight,
118	                                    const float* __restrict__ bias, int N, int C) {
119	    cg::thread_block block = cg::this_thread_block();
120	    cg::thread_block_tile<32> warp = cg::tiled_partition<32>(block);
121	    int idx = blockIdx.x * warp.meta_group_size() + warp.meta_group_rank();
122	    if(idx >= N) {
123	        return;
124	    }
125	
126	    // the row of input that this group of threads is responsible for
127	    const float* x = inp + idx * C;
128	
129	    // mean
130	    float sum = 0.0f;
131	    for (int i = warp.thread_rank(); i < C; i += warp.size()) {
132	        sum += x[i];
133	    }
134	    sum = cg::reduce(warp, sum, cg::plus<float>{});
135	    float m = sum / C;
136	    if(warp.thread_rank() == 0 && mean != nullptr) {
137	        __stcs(mean + idx, m);
138	    }
139	
140	    // rstd
141	    sum = 0.0f;
142	    for (int i = warp.thread_rank(); i < C; i += warp.size()) {
143	        float diff = x[i] - m;
144	        sum += diff * diff;
145	    }
146	    sum = cg::reduce(warp, sum, cg::plus<float>{});
147	    float s = rsqrtf(sum / C + 1e-5f);
148	    if(warp.thread_rank() == 0 && rstd != nullptr) {
149	        __stcs(rstd + idx, s);
150	    }
151	
152	    // final normalization and scaling by weight/bias
153	    float* o = out + idx * C;
154	    for (int c = warp.thread_rank(); c < C; c += warp.size()) {
155	        // load and store using the .cs "streaming" hint to the compiler,
156	        // indicating that this data will not be reused soon, and can be streamed through the caches
157	        // this allows the threads to get more cache-hits for the (shared) weight and bias parameters
158	        float n = s * (__ldcs(x+c) - m);
159	        __stcs(o+c, n * weight[c] + bias[c]);
160	    }
161	}
