163	__global__ void permute_kernel(float* q, float* k, float* v,
164	                               const float* inp,
165	                               int B, int N, int NH, int d) {
166	    // okay so now, this kernel wants Q,K,V to all be of shape (B, NH, N, d)
167	    // but instead, we have a single tensor QKV (inp) of shape (B, N, 3, NH, d)
168	    int idx = blockIdx.x * blockDim.x + threadIdx.x;
169	    // Q[b][nh_][n][d_] = inp[b][n][0][nh_][d_]
170	    if (idx < B * NH * N * d) {
171	        int b = idx / (NH * N * d);
172	        int rest = idx % (NH * N * d);
173	        int nh_ = rest / (N * d);
174	        rest = rest % (N * d);
175	        int n = rest / d;
176	        int d_ = rest % d;
177	        int inp_idx = (b * N * 3 * NH * d) + (n * 3 * NH * d) + (0 * NH * d) + (nh_ * d) + d_;
178	        q[idx] = __ldcs(&inp[inp_idx]);
179	        k[idx] = __ldcs(&inp[inp_idx + NH * d]);
180	        v[idx] = __ldcs(&inp[inp_idx + 2 * (NH * d)]);
181	    }
182	}
