184	__global__ void permute_kernel_backward(float* dinp,
185	                                        const float* dq, const float* dk, const float* dv,
186	                                        int B, int N, int NH, int d) {
187	    int idx = blockIdx.x * blockDim.x + threadIdx.x;
188	    if (idx < B * NH * N * d) {
189	        int b = idx / (NH * N * d);
190	        int rest = idx % (NH * N * d);
191	        int nh_ = rest / (N * d);
192	        rest = rest % (N * d);
193	        int n = rest / d;
194	        int d_ = rest % d;
195	
196	        int inp_idx = (b * N * 3 * NH * d) + (n * 3 * NH * d) + (0 * NH * d) + (nh_ * d) + d_;
197	        dinp[inp_idx] = dq[idx];
198	        dinp[inp_idx + NH * d] = dk[idx];
199	        dinp[inp_idx + 2 * (NH * d)] = dv[idx];
200	    }
201	}
