203	__global__ void unpermute_kernel(float* inp, float *out, int B, int N, int NH, int d) {
204	   // out has shape (B, nh, N, d) but we need to unpermute it to (B, N, nh, d)
205	    int idx = blockIdx.x * blockDim.x + threadIdx.x;
206	    // out[b][n][nh_][d_] <- inp[b][nh_][n][d_]
207	    if (idx < B * NH * N * d) {
208	        int b = idx / (NH * N * d);
209	        int rest = idx % (NH * N * d);
210	        int nh_ = rest / (N * d);
211	        rest = rest % (N * d);
212	        int n = rest / d;
213	        int d_ = rest % d;
214	        int other_idx = (b * NH * N * d) + (n * NH * d) + (nh_ * d) + d_;
215	        out[other_idx] = __ldcs(&inp[idx]);
216	    }
217	}
