219	__global__ void unpermute_kernel_backward(float* dinp, const float *dout, int B, int N, int NH, int d) {
220	    int idx = blockIdx.x * blockDim.x + threadIdx.x;
221	    if (idx < B * NH * N * d) {
222	        int b = idx / (NH * N * d);
223	        int rest = idx % (NH * N * d);
224	        int nh_ = rest / (N * d);
225	        rest = rest % (N * d);
226	        int n = rest / d;
227	        int d_ = rest % d;
228	        int other_idx = (b * NH * N * d) + (n * NH * d) + (nh_ * d) + d_;
229	        dinp[idx] = dout[other_idx];
230	    }
231	}
