241	__global__ void softmax_forward_kernel5(float* out, float inv_temperature, const float* inp, int N, int T) {
242	    // inp, out shape: (N, T, T), where N = B * NH
243	    // fuses the multiplication by scale inside attention
244	    // directly autoregressive, so we only compute the lower triangular part
245	    // uses the online softmax algorithm
246	    assert(T % 4  == 0);
247	    cg::thread_block block = cg::this_thread_block();
248	    cg::thread_block_tile<32> warp = cg::tiled_partition<32>(block);
249	    // micro-optimization: we iterate backwards so that
250	    // after the softmax backward operation completes, the cache retains the
251	    // part of the matrix close to the upper left corner, which benefits the
252	    // matmul operation that immediately follows.
253	    // int idx = blockIdx.x * warp.meta_group_size() + warp.meta_group_rank(); // forward order
254	    int idx = (gridDim.x - blockIdx.x - 1) * warp.meta_group_size() + warp.meta_group_rank(); // backward order
255	    if(idx >= N * T) {
256	        return;
257	    }
258	    int own_pos = idx % T;
259	    int pos_by_4 = own_pos / 4;
260	
261	    // one row of inp, i.e. inp[idx, :] of shape (T,)
262	    const float* x = inp + idx * T;
263	
264	    // not INF, so we don't get NaNs accidentally when subtracting two values.
265	    float maxval = -FLT_MAX;
266	    float sumval = 0.0f;
267	
268	    const float4* x_vec = reinterpret_cast<const float4*>(x);
269	    for (int i = warp.thread_rank(); i < pos_by_4; i += warp.size()) {
270	        float4 v = x_vec[i];
271	        float old_maxval = maxval;
272	        for(int k = 0; k < 4; ++k) {
273	            maxval = fmaxf(maxval, vec_at(v, k));
274	        }
275	        sumval *= expf(inv_temperature * (old_maxval - maxval));
276	        for(int k = 0; k < 4; ++k) {
277	            sumval += expf(inv_temperature * (vec_at(v, k) - maxval));
278	        }
279	    }
280	
281	    if(4*pos_by_4 + warp.thread_rank() <= own_pos) {
282	        float old_maxval = maxval;
283	        maxval = fmaxf(maxval, x[4*pos_by_4 + warp.thread_rank()]);
284	        sumval *= expf(inv_temperature * (old_maxval - maxval));
285	        sumval += expf(inv_temperature * (x[4*pos_by_4 + warp.thread_rank()] - maxval));
286	    }
287	
288	    float global_maxval = cg::reduce(warp, maxval, cg::greater<float>{});
289	    sumval *= expf(inv_temperature * (maxval - global_maxval));
290	
291	    float sum = cg::reduce(warp, sumval, cg::plus<float>{});
292	    float norm = 1.f / sum;
293	
294	    // divide the whole row by the sum
295	    for (int i = warp.thread_rank(); i <= own_pos; i += warp.size()) {
296	        // recalculation is faster than doing the round-trip through memory.
297	        float ev = expf(inv_temperature * (__ldcs(x + i) - global_maxval));
298	        __stcs(out + idx * T + i, ev * norm);
299	    }
300	}
301	
302	__global__ void residual_forward_kernel(float* out, float* inp1, float* inp2, int N) {
303	    int idx = blockIdx.x * blockDim.x + threadIdx.x;
304	    if (idx < N) {
305	        out[idx] = __ldcs(&inp1[idx]) + __ldcs(&inp2[idx]);
306	    }
307	}
308	
309	#define GELU_SCALING_FACTOR sqrtf(2.0f / M_PI)
310	__global__ void gelu_forward_kernel(float* out, const float* inp, int N) {
311	    int i = blockIdx.x * blockDim.x + threadIdx.x;
312	    if (i < N) {
313	        float xi = inp[i];
314	        float cube = 0.044715f * xi * xi * xi;
315	        out[i] = 0.5f * xi * (1.0f + tanhf(GELU_SCALING_FACTOR * (xi + cube)));
316	    }
317	}
318	
319	__global__ void gelu_backward_kernel(float* dinp, const float* inp, const float* dout, const int N) {
320	    int i = blockIdx.x * blockDim.x + threadIdx.x;
321	    if (i < N) {
322	        float x = inp[i];
323	        float cube = 0.044715f * x * x * x;
324	        float tanh_arg = GELU_SCALING_FACTOR * (x + cube);
325	        float tanh_out = tanhf(tanh_arg);
326	        float coshf_out = coshf(tanh_arg);
327	        float sech_out = 1.0f / (coshf_out * coshf_out);
328	        float local_grad = 0.5f * (1.0f + tanh_out) + x * 0.5f * sech_out * GELU_SCALING_FACTOR * (1.0f + 3.0f * 0.044715f * x * x);
329	        dinp[i] = local_grad * dout[i];
330	    }
331	}
