333	// this kernel performs a column-wise reduction over dout, in PyTorch equivalent to:
334	// dbias = dout.sum((0,1))
335	// the idea is to employ one block to reduce along several columns,
336	// where each block has a width of 32 columns to ensure coalesced access.
337	// at the end we accumulate the reductions performed by the warps in each block via shared memory
338	__global__ void matmul_backward_bias_kernel4(float* dbias, const float* dout, int B, int T, int OC) {
339	    // this kernel is launched with 1D grid_dim of OC/32
340	    // for example let's say block_size is 128
341	    extern __shared__ float smem[]; // of size block_size (128)
342	    const int warp_id = threadIdx.x / warpSize; // warp index in the block, 0,1,2,3
343	    const int lane_id = threadIdx.x % warpSize; // thread index in the warp, 0,1,2,...,31
344	    const int tl = blockIdx.x * warpSize; // pointer to the start column for this block
345	    const int vstep = blockDim.x / warpSize; // number of warps in a block, e.g. 4
346	
347	    // pointer to the start of the column for one lane of threads
348	    // so e.g. 4 threads (of the same lane_id) will reduce this one column
349	    const float* dout_col = dout + tl + lane_id;
350	
351	    // column reductions by looping through the rows
352	    // each of the 4 threads offsets by its warp_id and then skips by vstep
353	    // together these 4 threads cover all B*T rows of this (lane_id) column
354	    // importantly, consecutive threads (in threadId) are processing adjacent columns,
355	    // leading to a coalesced memory access pattern
356	    float dout_sum = 0.0f;
357	    for (int row = warp_id; row < B * T; row += vstep) {
358	        dout_sum += dout_col[row * OC];
359	    }
360	    smem[lane_id + warp_id * warpSize] = dout_sum;
361	    __syncthreads();
362	
363	    // warp_id 0 reduces the shared memory column-wise, linearly
364	    dout_sum = 0.0f;
365	    if (warp_id == 0) {
366	        for (int j = 0; j < vstep; j++) {
367	            dout_sum += smem[lane_id + j * warpSize];
368	        }
369	        dbias[tl + lane_id] += dout_sum;
370	    }
371	}
372	
373	// uses shared memory instead for the reduces
374	__global__ void layernorm_backward_kernel2(float* dinp, float* dweight, float* dbias,
375	                                           const float* dout, const float* inp, const float* weight, const float* mean, const float* rstd,
376	                                           int B, int T, int C) {
377	    extern __shared__ float shared[]; // size = 2 * C
378	
379	    namespace cg = cooperative_groups;
380	    cg::thread_block block = cg::this_thread_block();
381	    cg::thread_block_tile<32> warp = cg::tiled_partition<32>(block);
382	    int idx = blockIdx.x * warp.meta_group_size() + warp.meta_group_rank();
383	    int N = B * T;
384	    if(idx >= N) { return; } // thread guards
385	
386	    int b = idx / T;
387	    int t = idx % T;
388	
389	    const float* dout_bt = dout + b * T * C + t * C;
390	    const float* inp_bt = inp + b * T * C + t * C;
391	    float* dinp_bt = dinp + b * T * C + t * C;
392	    const float mean_bt = mean[b * T + t];
393	    const float rstd_bt = rstd[b * T + t];
394	
395	    // the first half of shared memory is bias, second is weight
396	    float* dbias_shared = shared;
397	    float* dweight_shared = shared + C;
398	
399	    // init shared memory to zero
400	    #pragma unroll
401		for(int i = threadIdx.x; i < C; i+= blockDim.x){
402	       dbias_shared[i] = 0.0f;
403	       dweight_shared[i] = 0.0f;
404	    }
405	    __syncthreads();
406	
407	    // first: two reduce operations
408	    float dnorm_mean = 0.0f;
409	    float dnorm_norm_mean = 0.0f;
410	    for (int i = warp.thread_rank(); i < C; i  += warp.size()) {
411	        float norm_bti = (inp_bt[i] - mean_bt) * rstd_bt;
412	        float dnorm_i = weight[i] * dout_bt[i];
413	        dnorm_mean += dnorm_i;
414	        dnorm_norm_mean += dnorm_i * norm_bti;
415	    }
416	    dnorm_mean = cg::reduce(warp, dnorm_mean, cg::plus<float>{});
417	    dnorm_norm_mean = cg::reduce(warp, dnorm_norm_mean, cg::plus<float>{});
418	    dnorm_mean = dnorm_mean / C;
419	    dnorm_norm_mean = dnorm_norm_mean / C;
420	
421	    // now iterate again and accumulate all the gradients
422	    for (int i = warp.thread_rank(); i < C; i += warp.size()) {
423	        float norm_bti = (inp_bt[i] - mean_bt) * rstd_bt;
424	        float dnorm_i = weight[i] * dout_bt[i];
425	        // gradient contribution to bias
426	        atomicAdd(&dbias_shared[i], dout_bt[i]);
427	        // gradient contribution to weight
428	        atomicAdd(&dweight_shared[i], norm_bti * dout_bt[i]);
429	        // gradient contribution to input
430	        float dval = 0.0f;
431	        dval += dnorm_i; // term 1
432	        dval -= dnorm_mean; // term 2
433	        dval -= norm_bti * dnorm_norm_mean; // term 3
434	        dval *= rstd_bt; // final scale
435	        dinp_bt[i] += dval;
436	    }
437	    __syncthreads();
438	
439	    // write to global memory
440		for(int i = threadIdx.x; i < C; i+= blockDim.x){
441	        atomicAdd(&dbias[i], dbias_shared[i]);
442	        atomicAdd(&dweight[i], dweight_shared[i]);
443		}
444	}
445	
446	__global__ void softmax_autoregressive_backward_kernel(float* dpreatt, const float* datt, const float* att,
447	                                                       int B, int T, int C, float scale) {
448	    constexpr const int BlockSize = 256;
449	    constexpr int T_per_block = 4;
450	    cg::thread_block block = cg::this_thread_block();
451	    cg::thread_block_tile<32> warp = cg::tiled_partition<32>(block);
452	    __shared__ float block_acc[32];
453	
454	    int idx = blockIdx.y;
455	    // go through blocks in reverse order, so the slowest block starts first
456	    int t0 = T - 1 - T_per_block*blockIdx.x;
457	
458	    att += idx * T * T;
459	    datt += idx * T * T;
460	    dpreatt += idx * T * T;
461	
462	    if (warp.meta_group_rank() == 0) {
463	        block_acc[warp.thread_rank()] = 0;
464	    }
465	
466	    for(int to = 0; to < T_per_block; ++to) {
467	        int t = t0 - to;
468	        if(t < 0) return;
469	        const float* att_bth = att + t * T;
470	        const float* datt_bth = datt + t * T;
471	        float* dpreatt_bth = dpreatt + t * T;
472	
473	        float local_sum = 0;
474	        for (int t2 = block.thread_rank(); t2 <= t; t2 += BlockSize) {
475	            local_sum += att_bth[t2] * datt_bth[t2];
476	        }
477	
478	        block_acc[warp.meta_group_rank()] = cg::reduce(warp, local_sum, cg::plus<float>{});
479	        block.sync();
480	        local_sum = cg::reduce(warp, block_acc[warp.thread_rank()], cg::plus<float>{});
481	
482	        for (int t3 = block.thread_rank(); t3 <= t; t3 += BlockSize) {
483	            // don't touch the cache. Some parts will still be here from the previous loop, and
484	            // we want to exploit those.
485	            float acc = __ldcs(att_bth + t3) * (__ldcs(datt_bth + t3) - local_sum);
486	            __stcs(dpreatt_bth + t3, scale * acc);
487	        }
488	    }
489	}
