491	// Implements linear interpolation using only two floating-point operations (as opposed to three in a naive implementation).
492	// Reference: https://developer.nvidia.com/blog/lerp-faster-cuda
493	__device__ inline float lerp(float start, float end, float weight) {
494	    return fma(weight, end, fma(-weight, start, start));
495	}
496	
497	__global__ void adamw_kernel2(float* params_memory, float* grads_memory, float* m_memory, float* v_memory, long num_parameters,
498	                              float learning_rate, float beta1, float beta2, float beta1_correction, float beta2_correction, float eps, float weight_decay) {
499	   int i = blockIdx.x * blockDim.x + threadIdx.x;
500	   if (i >= num_parameters) return;  // guard
501	   float grad = grads_memory[i];
502	   float m = m_memory[i];
503	   float v = v_memory[i];
504	   // update the first moment (momentum)
505	   m = lerp(grad, m, beta1);
506	   m_memory[i] = m;
507	   // update the second moment (RMSprop)
508	   v = lerp(grad * grad, v, beta2);
509	   v_memory[i] = v;
510	   m /= beta1_correction;  // m_hat
511	   v /= beta2_correction;  // v_hat
512	   params_memory[i] -= learning_rate * (m / (sqrtf(v) + eps) + weight_decay * params_memory[i]);
513	}
