515	struct SoftmaxParams {
516	    float Scale;
517	    float Offset;
518	};
519	
520	
521	__device__ SoftmaxParams prepare_softmax_blockwide_nofloat4(cg::thread_block_tile<32>& warp,
522	                                                   int idx, const float* inp, int V, int P) {
523	    // same but not float4
524	    // one row of inp, i.e. inp[idx, :] of shape (V,)
525	
526	    const float* x = inp + idx * P;
527	    float thread_maxval = -INFINITY;
528	    float thread_sumval = 0.0f;
529	    // do the loop in reverse to maximise probability of L2 cache hits
530	    // so even small L2s get some hits on the 2nd read of the same thread
531	    for (int i = V + threadIdx.x - blockDim.x; i >= 0; i -= blockDim.x) {
532	        float v = x[i];
533	        float old_maxval = thread_maxval;
534	        thread_maxval = fmaxf(thread_maxval, v);
535	        thread_sumval *= expf((old_maxval - thread_maxval));
536	        thread_sumval += expf(v - thread_maxval);
537	    }
538	
539	    // two reductions of up to 1024 threads:
540	    // 1) inside warp (shuffle), 2) cross-warp (shared memory), 3) inside warp (shuffle)
541	    // this results in much cleaner assembly than a multi-warp cg::reduce
542	    __shared__ float shared_maxval[32];
543	    __shared__ float shared_sumval[32];
544	    int num_warps = blockDim.x / 32;
545	    int warp_id = threadIdx.x / 32;
546	    int lane_id = threadIdx.x % 32;
547	
548	    // reduce maxval within each warp
549	    float warp_maxval = cg::reduce(warp, thread_maxval, cg::greater<float>{});
550	    // thread 0 in each warp writes to shared memory
551	    if (lane_id == 0) { shared_maxval[warp_id] = warp_maxval; }
552	    __syncthreads();
553	    // each thread now loads the maxval across previous warps
554	    // if the thread is "out of range" of data, use -FLT_MAX as the maxval
555	    warp_maxval = (lane_id < num_warps) ? shared_maxval[lane_id] : -FLT_MAX;
556	    // now reduce the maxval among the warp threads
557	    float block_maxval = cg::reduce(warp, warp_maxval, cg::greater<float>{});
558	    // each thread uses maxval to scale sumval to avoid numerical instability / overflow
559	    thread_sumval *= expf(thread_maxval - block_maxval);
560	    // (warp-level) reduce sumval, thread 0 in each warp saves result in shared memory
561	    float warp_sumval = cg::reduce(warp, thread_sumval, cg::plus<float>{});
562	    if (lane_id == 0) { shared_sumval[warp_id] = warp_sumval; }
563	    __syncthreads();
564	    // same strategy, now reduce sumval across warps
565	    warp_sumval = (lane_id < num_warps) ? shared_sumval[lane_id] : 0.0f;
566	    float block_sumval = cg::reduce(warp, warp_sumval, cg::plus<float>{});
567	    // return the softmax parameters
568	    return SoftmaxParams{1.f / block_sumval, block_maxval};
569	}
