571	// same as 2 but not using float4 (see dev/cuda/classifier_fused.cu)
572	// will _update_ logits to logit gradients
573	__global__ void fused_classifier_kernel3(float* logits, float* losses, float* probs,
574	                                         const float* dlosses, const int* targets,
575	                                         int B, int T, int V, int P) {
576	    namespace cg = cooperative_groups;
577	    cg::thread_block block = cg::this_thread_block();
578	    cg::thread_block_tile<32> warp = cg::tiled_partition<32>(block);
579	    int idx = blockIdx.x;
580	    int ix = targets[idx];
581	
582	    // softmax (reading B * T * V, same logits read again below, hopefully still in cache)
583	    SoftmaxParams sp = prepare_softmax_blockwide_nofloat4(warp, idx, logits, V, P);
584	
585	    // calculate the probability needed for the loss and update (single-threaded)
586	    if(threadIdx.x == 0) {
587	        float prob = expf(logits[idx * P + ix] - sp.Offset) * sp.Scale;
588	        losses[idx] = -logf(prob);
589	    }
590	
591	    // very sensible default for dlosses is 1/(B*T), which is the uniform loss
592	    float dloss = dlosses != NULL ? dlosses[idx] : 1.0f / (B*T);
593	    // calculate the gradients directly, saves bandwidth from probs during training
594	    // but also supports writing probs for inference-only and debugging
595	    const float* logits_vec = logits + idx * P;
596	    for (int i = threadIdx.x; i < V; i += blockDim.x) {
597	        // this is the 2nd read of logits after the one in prepare_softmax2
598	        // this data will never be needed again, so we reduce cache persistence
599	        float v = __ldcs(&logits_vec[i]);
600	        float prob = expf(v - sp.Offset) * sp.Scale;
601	        if (probs != NULL) {
602	            probs[idx * P + i] = prob;
603	        }
604	        float indicator = (i == ix) ? 1.0f : 0.0f;
605	        logits[idx * P + i] = (prob - indicator) * dloss;
606	    }
607	}
