609	__device__ float4 ld_vec(const float* address) {
610	    return *reinterpret_cast<const float4*>(address);
611	}
612	
613	__device__ void st_vec(float* address, float4 val) {
614	    *reinterpret_cast<float4*>(address) = val;
615	}
616	
617	__global__ void __launch_bounds__(16*16, 2) matmul_forward_kernel4(float* out,
618	                                                                   const float* inp, const float* weight, const float* bias,
619	                                                                   int C, int OC) {
620	    // out is (B,T,OC). OC is short for "output channels", e.g. OC = 4 * C
621	    // inp is (B,T,C), weight is (OC, C), bias is (OC)
622	    // each thread handles 8x8 elements; each block 128 by 128 elements.
623	    int oc = 8*(blockIdx.y * blockDim.y + threadIdx.y);
624	
625	    // buffers to cache chunks of the input matrices
626	    __shared__ float lhs_s[128][32];
627	    __shared__ float rhs_s[128][32];
628	
629	    // adjust our pointers for the current block
630	    inp += 128 * blockIdx.x * C;
631	    weight += 128 * blockIdx.y * C;
632	    out += 128 * blockIdx.x * OC + 128 * blockIdx.y;
633	
634	    float vals[8][8] = {};
635	    if(bias != NULL) {
636	        for (int i = 0; i < 8; i++) {
637	            for (int j = 0; j < 8; j += 4) {
638	                float4 b = ld_vec(bias + oc + j);
639	                vals[i][j+0] = b.x;
640	                vals[i][j+1] = b.y;
641	                vals[i][j+2] = b.z;
642	                vals[i][j+3] = b.w;
643	            }
644	        }
645	    }
646	
647	    int si_start = 4*(16 * threadIdx.y + threadIdx.x);
648	    for (int so = 0; so < C; so += 32) {
649	        __syncthreads();
650	        int xmod8 = threadIdx.x % 8;
651	        int xby8 = threadIdx.x / 8;
652	        int xo = 4 * xmod8;
653	        for(int y = 2 * threadIdx.y + xby8; y < 128; y += 32) {
654	            st_vec(&lhs_s[y][xo], ld_vec(inp + y * C + so + xo));
655	            st_vec(&rhs_s[y][xo], ld_vec(weight + y * C + so + xo));
656	        }
657	        __syncthreads();
658	
659	        for (int si = si_start; si < si_start + 32; si += 4) {
660	            float4 rhs[8];
661	            for (int u = 0; u < 8; ++u) {
662	                rhs[u] = ld_vec(&rhs_s[u + 8 * threadIdx.y][si % 32]);
663	            }
664	
665	            for (int ii = 0; ii < 8; ++ii) {
666	                float4 lhs = ld_vec(&lhs_s[ii + 8 * threadIdx.x][si % 32]);
667	                for (int ji = 0; ji < 8; ++ji) {
668	                    vals[ii][ji] += lhs.x * rhs[ji].x;
669	                    vals[ii][ji] += lhs.y * rhs[ji].y;
670	                    vals[ii][ji] += lhs.z * rhs[ji].z;
671	                    vals[ii][ji] += lhs.w * rhs[ji].w;
672	                }
673	            }
674	        }
675	    }
676	
677	    for (int i = 0; i < 8; ++i) {
678	        for (int j = 0; j < 8; j += 4) {
679	            float4 result;
680	            result.x = vals[i][j + 0];
681	            result.y = vals[i][j + 1];
682	            result.z = vals[i][j + 2];
683	            result.w = vals[i][j + 3];
684	            st_vec(out + (8*threadIdx.x+i) * OC + 8*threadIdx.y + j, result);
685	        }
686	    }
687	}
