738	void attention_forward(float* out, float* qkvr, float* att,
739	                       float* inp,
740	                       int B, int T, int C, int NH) {
741	    // Note: `inp` is not needed for backward pass, so we re-use it as a scratch buffer.
742	    // Its contents will be overwritten by this function.
743	    const int block_size = 256;
744	    const int softmax_block_size = 256;
745	
746	    // inp is (B, T, 3C) QKV
747	    // preatt, att are (B, NH, T, T)
748	    // output is (B, T, C)
749	    int HS = C / NH; // head size
750	
751	    // permute and separate inp from (B, T, 3, NH, HS) to 3X (B, NH, T, HS)
752	    float *q, *k, *v;
753	    q = qkvr + 0 * B * T * C;
754	    k = qkvr + 1 * B * T * C;
755	    v = qkvr + 2 * B * T * C;
756	    int total_threads = B * NH * T * HS;
757	    int num_blocks = CEIL_DIV(total_threads, block_size);
758	    permute_kernel<<<num_blocks, block_size>>>(q, k, v, inp, B, T, NH, HS);
759	    cudaCheck(cudaGetLastError());
760	
761	    // batched matrix multiply with cuBLAS
762	    const float alpha = 1.0f;
763	    const float beta = 0.0f;
764	    float* preatt = inp;
765	    cublasCheck(cublasSgemmStridedBatched(cublas_handle, CUBLAS_OP_T, CUBLAS_OP_N, T, T, HS, &alpha, k, HS, T * HS, q, HS, T * HS, &beta, preatt, T, T * T, B * NH));
766	
767	    // multiply all elements of preatt elementwise by scale
768	    float scale = 1.0 / sqrtf(HS);
769	    int grid_size = CEIL_DIV(B * NH * T * 32, softmax_block_size);
770	    softmax_forward_kernel5<<<grid_size, softmax_block_size>>>(att, scale, preatt, B * NH, T);
771	    cudaCheck(cudaGetLastError());
772	
773	    // new approach: first cuBLAS another batched matmul
774	    float* vaccum = inp;
775	    // y = att @ v # (B, nh, T, T) @ (B, nh, T, hs) -> (B, nh, T, hs)
776	    cublasCheck(cublasSgemmStridedBatched(cublas_handle, CUBLAS_OP_N, CUBLAS_OP_N, HS, T, T, &alpha, v, HS, T * HS, att, T, T * T, &beta, vaccum, HS, T * HS, B * NH));
777	
778	    // now unpermute
779	    // y = y.transpose(1, 2).contiguous().view(B, T, C) # re-assemble all head outputs side by side
780	    num_blocks = CEIL_DIV(B * T * C, block_size);
781	    unpermute_kernel<<<num_blocks, block_size>>>(vaccum, out, B, T, NH, HS);
782	    cudaCheck(cudaGetLastError());
783	}
