835	// the sequence of transformations in this compound op is:
836	// inp (B,T,3C) -> qkvr (B,T,3C) -> preatt (B,NH,T,T) -> att (B,NH,T,T) -> vaccum (B,T,C) -> out (B,T,C)
837	void attention_backward(float* dinp, float* dqkvr, float* dpreatt, float* datt, float* scratch,
838	                        const float* dout,
839	                        const float* qkvr, const float* att,
840	                        int B, int T, int C, int NH) {
841	    const int block_size = 256;
842	    int HS = C / NH; // head size
843	    const float one = 1.0f;
844	    const float zero = 0.0f; // note beta = 1.0f so that we accumulate gradients (+=)
845	    // unpack convenience pointers into q, k, v
846	    const float *q, *k, *v;
847	    q = qkvr + 0 * B * T * C;
848	    k = qkvr + 1 * B * T * C;
849	    v = qkvr + 2 * B * T * C;
850	    float *dq, *dk, *dv;
851	    dq = dqkvr + 0 * B * T * C;
852	    dk = dqkvr + 1 * B * T * C;
853	    dv = dqkvr + 2 * B * T * C;
854	    // backward through the unpermute operation
855	    int num_blocks = CEIL_DIV(B * T * C, block_size);
856	    unpermute_kernel_backward<<<num_blocks, block_size>>>(scratch, dout, B, T, NH, HS);
857	    cudaCheck(cudaGetLastError());
858	    // backward into datt
859	    cublasCheck(cublasSgemmStridedBatched(cublas_handle, CUBLAS_OP_T, CUBLAS_OP_N, T, T, HS, &one, v, HS, T * HS, scratch, HS, T * HS, &zero, datt, T, T * T, B * NH));
860	    // backward into dv
861	    cublasCheck(cublasSgemmStridedBatched(cublas_handle, CUBLAS_OP_N, CUBLAS_OP_T, HS, T, T, &one, scratch, HS, T * HS, att, T, T * T, &zero, dv, HS, T * HS, B * NH));
862	    // backward into preatt
863	    int hs = C / NH; // head size
864	    float scale = 1.0f / sqrtf(hs);
865	    softmax_autoregressive_backward_kernel<<<dim3(T / 4, B * NH), 256>>>(dpreatt, datt, att, B, T, C, scale);
866	    cudaCheck(cudaGetLastError());
867	    // backward into q
868	    cublasCheck(cublasSgemmStridedBatched(cublas_handle, CUBLAS_OP_N, CUBLAS_OP_N, HS, T, T, &one, k, HS, T * HS, dpreatt, T, T * T, &zero, dq, HS, T * HS, B * NH));
869	    // backward into k
870	    cublasCheck(cublasSgemmStridedBatched(cublas_handle, CUBLAS_OP_N, CUBLAS_OP_T, HS, T, T, &one, q, HS, T * HS, dpreatt, T, T * T, &zero, dk, HS, T * HS, B * NH));
871	    // backward into inp
872	    num_blocks = CEIL_DIV(B * NH * T * HS, block_size);
873	    permute_kernel_backward<<<num_blocks, block_size>>>(dinp, dq, dk, dv, B, T, NH, HS);
874	    cudaCheck(cudaGetLastError());
875	}
