924	    int maxT = config.max_seq_len;
925	    int L = config.num_layers;
926	    param_sizes[0] = Vp * C; // wte
927	    param_sizes[1] = maxT * C; // wpe
928	    param_sizes[2] = L * C; // ln1w
929	    param_sizes[3] = L * C; // ln1b
930	    param_sizes[4] = L * (3 * C) * C; // qkvw
931	    param_sizes[5] = L * (3 * C); // qkvb
932	    param_sizes[6] = L * C * C; // attprojw
933	    param_sizes[7] = L * C; // attprojb
934	    param_sizes[8] = L * C; // ln2w
935	    param_sizes[9] = L * C; // ln2b
936	    param_sizes[10] = L * (4 * C) * C; // fcw
937	    param_sizes[11] = L * (4 * C); // fcb
938	    param_sizes[12] = L * C * (4 * C); // fcprojw
939	    param_sizes[13] = L * C; // fcprojb
940	    param_sizes[14] = C; // lnfw
941	    param_sizes[15] = C; // lnfb
942	}
