944	// allocate memory for the parameters and point the individual tensors to the right places
945	float* malloc_and_point_parameters(ParameterTensors* params, size_t* param_sizes, int on_device) {
946	    // on_device: 0 = CPU, 1 = GPU
947	    // calculate the number of parameters
948	    size_t num_parameters = 0;
949	    for (size_t i = 0; i < NUM_PARAMETER_TENSORS; i++) {
950	        num_parameters += param_sizes[i];
951	    }
952	    // malloc all parameters all at once on the device
953	    float* params_memory;
954	    if (on_device) {
955	        cudaCheck(cudaMalloc((void**)&params_memory, num_parameters * sizeof(float)));
956	    } else {
957	        params_memory = (float*)mallocCheck(num_parameters * sizeof(float));
958	    }
959	    // assign all the tensors their place in the array
960	    float** ptrs[] = {
961	        &params->wte, &params->wpe, &params->ln1w, &params->ln1b, &params->qkvw, &params->qkvb,
962	        &params->attprojw, &params->attprojb, &params->ln2w, &params->ln2b, &params->fcw, &params->fcb,
963	        &params->fcprojw, &params->fcprojb, &params->lnfw, &params->lnfb
964	    };
965	    float* params_memory_iterator = params_memory;
966	    for (size_t i = 0; i < NUM_PARAMETER_TENSORS; i++) {
967	        *(ptrs[i]) = params_memory_iterator;
968	        params_memory_iterator += param_sizes[i];
969	    }
970	    return params_memory;
971	}
