973	#define NUM_ACTIVATION_TENSORS 21
974	typedef struct {
975	    float* encoded; // (B, T, C)
976	    float* ln1; // (L, B, T, C)
977	    float* ln1_mean; // (L, B, T)
978	    float* ln1_rstd; // (L, B, T)
979	    float* atty; // (L, B, T, C)
980	    float* att; // (L, B, NH, T, T)
981	    float* attproj; // (L, B, T, C)
982	    float* residual2; // (L, B, T, C)
983	    float* ln2; // (L, B, T, C)
984	    float* ln2_mean; // (L, B, T)
985	    float* ln2_rstd; // (L, B, T)
986	    float* fch; // (L, B, T, 4*C)
987	    float* fch_gelu; // (L, B, T, 4*C)
988	    float* fcproj; // (L, B, T, C)
989	    float* residual3; // (L, B, T, C)
990	    float* lnf; // (B, T, C)
991	    float* lnf_mean; // (B, T)
992	    float* lnf_rstd; // (B, T)
993	
994	    float* losses; // (B, T)
995	    // adding these two compared to the CPU .c code, needed for attention kernel as buffers
996	    float* qkvr; // (L, B, T, 3*C)
997	    // in inference mode, this buffer will store the logits
998	    // in training mode, this buffer will contain the *gradients* of the logits.
999	    // during the processing of transformer blocks, we will also use this as a
1000	    // general scratchpad buffer. Allocation is made large enough to hold (B, T, 3C),
1001	    // (B, NH, T, T), and (B, T, V) shaped tensors.
1002	    float* output;
1003	} ActivationTensors;
