1005	void fill_in_activation_sizes(size_t* act_sizes, int B, int T, GPT2Config config) {
1006	    size_t Vp = config.padded_vocab_size;
1007	    size_t L = config.num_layers;
1008	    size_t NH = config.num_heads;
1009	    size_t C = config.channels;
1010	    act_sizes[0] = B * T * C; // encoded
1011	    act_sizes[1] = L * B * T * C; // ln1
1012	    act_sizes[2] = L * B * T; // ln1_mean
1013	    act_sizes[3] = L * B * T; // ln1_rstd
1014	    act_sizes[4] = L * B * T * C; // atty
1015	    act_sizes[5] = L * B * NH * T * T; // att
1016	    act_sizes[6] = L * B * T * C; // attproj
1017	    act_sizes[7] = L * B * T * C; // residual2
1018	    act_sizes[8] = L * B * T * C; // ln2
1019	    act_sizes[9] = L * B * T; // ln2_mean
1020	    act_sizes[10] = L * B * T; // ln2_rstd
1021	    act_sizes[11] = L * B * T * 4*C; // fch
1022	    act_sizes[12] = L * B * T * 4*C; // fch_gelu
1023	    act_sizes[13] = L * B * T * C; // fcproj
1024	    act_sizes[14] = L * B * T * C; // residual3
1025	    act_sizes[15] = B * T * C; // lnf
1026	    act_sizes[16] = B * T; // lnf_mean
1027	    act_sizes[17] = B * T; // lnf_rstd
1028	    act_sizes[18] = B * T; // losses
1029	    act_sizes[19] = L * B * T * 3*C; // qkvr
1030	    act_sizes[20] = B * T * max(3*C, max(NH*T, Vp)); // output / scratch
1031	}
1032	
1033	// Backward pass is conceptually quite different from forward, because we can discard
1034	// the activations of a layer as soon as we're done with it. This lets us aggressively
1035	// reuse memory, so that we need far fewer tensors for backward state.
1036	#define NUM_BACKWARD_TENSORS 3
1037	typedef struct {
1038	    float* bt4c; // (B, T, 4*C)
1039	    float* preatt; // (B, NH, T, T)
1040	    float* residual3; // (B, T, C)
1041	} GradActTensors;
