1044	void fill_in_grad_act_sizes(size_t* act_sizes, int B, int T, GPT2Config config) {
1045	    size_t NH = config.num_heads;
1046	    size_t C = config.channels;
1047	    act_sizes[0] = B * T * 4 * C; // bt4c
1048	    act_sizes[1] = B * NH * T * T; // preatt
1049	    act_sizes[2] = B * T * C; // residual3
1050	}
