1053	float* malloc_and_point(float** targets[], const size_t* act_sizes, int n) {
1054	    size_t num_activations = 0;
1055	    for (size_t i = 0; i < n; i++) {
1056	        num_activations += act_sizes[i];
1057	    }
1058	    float* acts_memory;
1059	    cudaCheck(cudaMalloc((void**)&acts_memory, num_activations * sizeof(float)));
1060	    float* acts_memory_iterator = acts_memory;
1061	    for (size_t i = 0; i < n; i++) {
1062	        *(targets[i]) = acts_memory_iterator;
1063	        acts_memory_iterator += act_sizes[i];
1064	    }
1065	    return acts_memory;
1066	}
