1068	float* malloc_and_point_activations(ActivationTensors* acts, const size_t* act_sizes) {
1069	    float** ptrs[] = {
1070	        &acts->encoded, &acts->ln1, &acts->ln1_mean, &acts->ln1_rstd, &acts->atty,
1071	        &acts->att, &acts->attproj, &acts->residual2, &acts->ln2, &acts->ln2_mean,
1072	        &acts->ln2_rstd, &acts->fch, &acts->fch_gelu, &acts->fcproj, &acts->residual3, &acts->lnf,
1073	        &acts->lnf_mean, &acts->lnf_rstd, &acts->losses, &acts->qkvr, &acts->output
1074	    };
1075	    return malloc_and_point(ptrs, act_sizes, NUM_ACTIVATION_TENSORS);
