1085	typedef struct {
1086	    GPT2Config config;
1087	    // the weights of the model, and their sizes
1088	    ParameterTensors params;
1089	    size_t param_sizes[NUM_PARAMETER_TENSORS];
1090	    float* params_memory;
1091	    size_t num_parameters;
1092	    // gradients of the weights
1093	    ParameterTensors grads;
1094	    float* grads_memory;
1095	    // buffers for the AdamW optimizer
1096	    float* m_memory;
1097	    float* v_memory;
1098	    // the activations of the model, and their sizes
1099	    ActivationTensors acts;
1100	    size_t act_sizes[NUM_ACTIVATION_TENSORS];
1101	    float* acts_memory;
1102	    size_t num_activations;
1103	    // gradients of the activations
1104	    GradActTensors grads_acts;
