1109	    int seq_len; // the sequence length (T) of current forward pass
1110	    int* inputs; // the input tokens for the current forward pass
1111	    int* targets; // the target tokens for the current forward pass
1112	    float mean_loss; // after a forward pass with targets, will be populated with the mean loss
