1116	void gpt2_build_from_checkpoint(GPT2 *model, const char* checkpoint_path) {
1117	
1118	    // read in model from a checkpoint file
1119	    FILE *model_file = fopenCheck(checkpoint_path, "rb");
1120	    int model_header[256];
1121	    freadCheck(model_header, sizeof(int), 256, model_file);
1122	    if (model_header[0] != 20240326) { fprintf(stderr, "Bad magic model file\n"); exit(EXIT_FAILURE); }
1123	    if (model_header[1] != 3) {
1124	        // was bumped from 1 -> 3 to incorporate the padded vocab size
1125	        fprintf(stderr, "Bad version in model file\n");
1126	        fprintf(stderr, "---> HINT: try to re-run `python train_gpt2.py`\n");
1127	        exit(EXIT_FAILURE);
1128	    }
1129	
1130	    // read in hyperparameters
1131	    model->config.max_seq_len = model_header[2];
1132	    model->config.vocab_size = model_header[3];
1133	    model->config.num_layers = model_header[4];
1134	    model->config.num_heads = model_header[5];
1135	    model->config.channels = model_header[6];
1136	    model->config.padded_vocab_size = model_header[7];
1137	
1138	    // allocate space for all the parameters and read them in
1139	    fill_in_parameter_sizes(model->param_sizes, model->config);
1140	
1141	    // count the number of parameters
1142	    size_t num_parameters = 0;
1143	    for (size_t i = 0; i < NUM_PARAMETER_TENSORS; i++) {
1144	        num_parameters += model->param_sizes[i];
1145	    }
1146	    model->num_parameters = num_parameters;
1147	
1148	    // create memory for model parameters on the device
1149	    model->params_memory = malloc_and_point_parameters(&model->params, model->param_sizes, 1);
1150	
1151	    // read in all the parameters from file and copy them to device
1152	    float* params_memory_cpu = (float*)mallocCheck(num_parameters * sizeof(float));
1153	    freadCheck(params_memory_cpu, sizeof(float), num_parameters, model_file);
1154	    cudaCheck(cudaMemcpy(model->params_memory, params_memory_cpu, num_parameters * sizeof(float), cudaMemcpyHostToDevice));
1155	    free(params_memory_cpu);
1156	    fcloseCheck(model_file);
1157	
1158	    // other inits
1159	    model->acts_memory = NULL;
1160	    model->grads_memory = NULL;
1161	    model->m_memory = NULL;
1162	    model->v_memory = NULL;
1163	    model->grads_acts_memory = NULL;
1164	    model->inputs = NULL;
1165	    model->targets = NULL;
1166	    model->cpu_losses = NULL;
1167	    model->batch_size = 0;
1168	    model->seq_len = 0;
1169	    model->mean_loss = -1.0f; // -1.0f will designate no loss
1170	}
