1172	void gpt2_forward(GPT2 *model, int* inputs, int* targets, int B, int T) {
1173	    // targets are optional and could be NULL
1174	
1175	    // ensure the model was initialized or error out
1176	    if (model->params_memory == NULL) {
1177	        printf("Error: model was not initialized properly.\n");
1178	        exit(EXIT_FAILURE);
1179	    }
1180	
1181	    // convenience parameters
1182	    int V = model->config.vocab_size;
1183	    int Vp = model->config.padded_vocab_size;
1184	    int L = model->config.num_layers;
1185	    int NH = model->config.num_heads;
1186	    int C = model->config.channels;
1187	
1188	    // validate inputs, all indices must be in the range [0, V)
1189	    for(int i = 0; i < B * T; i++) {
1190	        assert(0 <= inputs[i] && inputs[i] < V);
1191	        if (targets != NULL) {
1192	            assert(0 <= targets[i] && targets[i] < V);
1193	        }
1194	    }
1195	
1196	    // allocate space for all the activations if needed (done here, lazily)
1197	    if(model->acts_memory == NULL) {
1198	        // record the current B,T as well
1199	        model->batch_size = B;
1200	        model->seq_len = T;
1201	        // and now allocate the space
1202	        fill_in_activation_sizes(model->act_sizes, B, T, model->config);
1203	        size_t num_activations = 0;
1204	        for (size_t i = 0; i < NUM_ACTIVATION_TENSORS; i++) {
1205	            num_activations += model->act_sizes[i];
1206	        }
1207	        model->num_activations = num_activations;
1208	        model->acts_memory = malloc_and_point_activations(&model->acts, model->act_sizes);
1209	        printf("allocated %zu MiB for activations\n", (num_activations * sizeof(float)) >> 20); // >> 20 is /(1024*1024)
1210	        // also create memory for caching inputs and targets
1211	        cudaCheck(cudaMalloc((void**)&model->inputs, B * T * sizeof(int)));
1212	        cudaCheck(cudaMalloc((void**)&model->targets, B * T * sizeof(int)));
1213	        cudaCheck(cudaMallocHost((void**)&model->cpu_losses, B * T * sizeof(float)));
1214	    } else {
1215	        // validate B,T is consistent with how we've allocated the memory before
1216	        // in principle we could get more clever here in the future, for now this is safest
1217	        if (B != model->batch_size || T != model->seq_len) {
1218	            printf("Model: B=%d T=%d, Desired: B=%d T=%d\n", model->batch_size, model->seq_len, B, T);
1219	            exit(EXIT_FAILURE);
1220	        }
1221	    }
1222	
1223	    // copy inputs/targets to the model
1224	    cudaCheck(cudaMemcpy(model->inputs, inputs, B * T * sizeof(int), cudaMemcpyHostToDevice));
1225	    if (targets != NULL) {
1226	        cudaCheck(cudaMemcpy(model->targets, targets, B * T * sizeof(int), cudaMemcpyHostToDevice));
1227	    }
1228	
1229	    // forward pass
1230	    ParameterTensors params = model->params; // for brevity
1231	    ActivationTensors acts = model->acts;
1232	    float* residual;
1233	    encoder_forward(acts.encoded, model->inputs, params.wte, params.wpe, B, T, C); // encoding goes into residual[0]
1234	
1235	    for (int l = 0; l < L; l++) {
1236	
1237	        residual = l == 0 ? acts.encoded : acts.residual3 + (l-1) * B * T * C;
1238	
1239	        // get the pointers of the weights for this layer
1240	        float* l_ln1w = params.ln1w + l * C;
1241	        float* l_ln1b = params.ln1b + l * C;
1242	        float* l_qkvw = params.qkvw + l * 3*C * C;
1243	        float* l_qkvb = params.qkvb + l * 3*C;
1244	        float* l_attprojw = params.attprojw + l * C * C;
1245	        float* l_attprojb = params.attprojb + l * C;
1246	        float* l_ln2w = params.ln2w + l * C;
1247	        float* l_ln2b = params.ln2b + l * C;
1248	        float* l_fcw = params.fcw + l * 4*C * C;
1249	        float* l_fcb = params.fcb + l * 4*C;
1250	        float* l_fcprojw = params.fcprojw + l * C * 4*C;
1251	        float* l_fcprojb = params.fcprojb + l * C;
1252	
1253	        // get the pointers of the activations for this layer
1254	        float* l_ln1 = acts.ln1 + l * B * T * C;
1255	        float* l_ln1_mean = acts.ln1_mean + l * B * T;
1256	        float* l_ln1_rstd = acts.ln1_rstd + l * B * T;
1257	        float* l_qkvr = acts.qkvr + l * B * T * 3*C;
1258	        float* l_atty = acts.atty + l * B * T * C;
1259	        float* l_att = acts.att + l * B * NH * T * T;
1260	        float* l_attproj = acts.attproj + l * B * T * C;
1261	        float* l_residual2 = acts.residual2 + l * B * T * C;
1262	        float* l_ln2 = acts.ln2 + l * B * T * C;
1263	        float* l_ln2_mean = acts.ln2_mean + l * B * T;
1264	        float* l_ln2_rstd = acts.ln2_rstd + l * B * T;
1265	        float* l_fch = acts.fch + l * B * T * 4*C;
1266	        float* l_fch_gelu = acts.fch_gelu + l * B * T * 4*C;
1267	        float* l_fcproj = acts.fcproj + l * B * T * C;
1268	        float* l_residual3 = acts.residual3 + l * B * T * C;
1269	        // these are only needed as scratchpads for the forward pass, but
1270	        // need not be stored for backward
1271	        float* scratch = acts.output;
1272	
1273	        // now do the forward pass
1274	        layernorm_forward(l_ln1, l_ln1_mean, l_ln1_rstd, residual, l_ln1w, l_ln1b, B, T, C);
1275	        matmul_forward(scratch, l_ln1, l_qkvw, l_qkvb, B, T, C, 3*C);
1276	        attention_forward(l_atty, l_qkvr, l_att, scratch, B, T, C, NH);
1277	        matmul_forward(l_attproj, l_atty, l_attprojw, l_attprojb, B, T, C, C);
1278	        residual_forward(l_residual2, residual, l_attproj, B*T*C);
1279	        layernorm_forward(l_ln2, l_ln2_mean, l_ln2_rstd, l_residual2, l_ln2w, l_ln2b, B, T, C);
1280	        matmul_forward(l_fch, l_ln2, l_fcw, l_fcb, B, T, C, 4*C);
1281	        gelu_forward(l_fch_gelu, l_fch, B*T*4*C);
1282	        matmul_forward(l_fcproj, l_fch_gelu, l_fcprojw, l_fcprojb, B, T, 4*C, C);
1283	        residual_forward(l_residual3, l_residual2, l_fcproj, B*T*C);
1284	    }
1285	
1286	    residual = acts.residual3 + (L-1) * B * T * C; // last residual is in residual3
1287	    layernorm_forward(acts.lnf, acts.lnf_mean, acts.lnf_rstd, residual, params.lnfw, params.lnfb, B, T, C);
1288	    matmul_forward(acts.output, acts.lnf, params.wte, NULL, B, T, C, Vp);
1289	
1290	    // also forward the cross-entropy loss function if we have the targets
1291	    if (targets != NULL) {
1292	        // fused classifier: does the forward pass and first part of the backward pass
1293	        // we're passing dlosses = NULL, which will default them to 1.0f/(B*T), i.e. uniform loss
1294	        fused_classifier3(acts.output, acts.losses, NULL, model->targets, B, T, V, Vp);
1295	        // for convenience also evaluate the mean loss (TODO re-think this compute+sync point)
1296	        // move the (B,T) losses to CPU
1297	        cudaCheck(cudaMemcpy(model->cpu_losses, acts.losses, B * T * sizeof(float), cudaMemcpyDeviceToHost));
1298	        float mean_loss = 0.0f;
1299	        for (int i=0; i<B*T; i++) { mean_loss += model->cpu_losses[i]; }
1300	        mean_loss /= B*T;
1301	        model->mean_loss = mean_loss;
1302	
1303	    } else {
1304	        // if we don't have targets, we don't have loss
1305	        model->mean_loss = -1.0f;
1306	    }
1307	}
