1309	void gpt2_zero_grad(GPT2 *model) {
1310	    if (model->grads_acts_memory != NULL) { cudaCheck(cudaMemset(model->grads_acts_memory, 0, model->num_grad_acts * sizeof(float))); }
1311	    if (model->grads_memory != NULL) { cudaCheck(cudaMemset(model->grads_memory, 0, model->num_parameters * sizeof(float))); }
1312	}
1313	
1314	void gpt2_backward(GPT2 *model) {
1315	
1316	    // double check we forwarded previously, with targets
1317	    if (model->mean_loss == -1.0f) {
1318	        printf("Error: must forward with targets before backward\n");
1319	        exit(EXIT_FAILURE);
1320	    }
1321	
1322	    // lazily allocate the memory for gradients of the weights and activations, if needed
1323	    if (model->grads_memory == NULL) {
1324	        // allocate buffers for weight gradients
1325	        model->grads_memory = malloc_and_point_parameters(&model->grads, model->param_sizes, 1);
1326	        printf("allocated %zu MiB for parameter gradients\n", (model->num_parameters * sizeof(float)) >> 20);
1327	        // we're going to be clever for the activations backward pass. we don't need to exactly
1328	        // mirror the forward pass acrtivations and we will save memory.
1329	        size_t bw_act_sizes[NUM_ACTIVATION_TENSORS];
1330	        GPT2Config cfg = model->config;
1331	        cfg.num_layers = 1; // copy the configuration but override number of layers to 1
1332	        fill_in_grad_act_sizes(bw_act_sizes, model->batch_size, model->seq_len, cfg);
1333	        // count up and allocate the space
1334	        model->grads_acts_memory = malloc_and_point_backward(&model->grads_acts, bw_act_sizes);
1335	        model->num_grad_acts = 0;
1336	        for (int i = 0; i < NUM_BACKWARD_TENSORS; i++) {
1337	            model->num_grad_acts += bw_act_sizes[i];
1338	        }
1339	        printf("allocated %zu MiB for activation gradients\n", (model->num_grad_acts * sizeof(float)) >> 20);
1340	        // init gradients of parameters and activations to zero
1341	        gpt2_zero_grad(model);
1342	    }
1343	
1344	    // convenience shortcuts
1345	    int B = model->batch_size;
1346	    int T = model->seq_len;
1347	    int Vp = model->config.padded_vocab_size;
1348	    int L = model->config.num_layers;
1349	    int NH = model->config.num_heads;
1350	    int C = model->config.channels;
1351	
1352	    // backward pass: go in the reverse order of the forward pass, and call backward() functions
1353	    ParameterTensors params = model->params; // for brevity
1354	    ParameterTensors grads = model->grads;
1355	    ActivationTensors acts = model->acts;
1356	    GradActTensors grads_acts = model->grads_acts;
1357	
1358	    // we kick off the chain rule by filling in dlosses with 1.0f/(B*T)
1359	    // this was done in the fused classifier kernel as last step of forward pass
1360	    // technically that is a small, inline backward() pass of calculating
1361	    // total, final loss as the mean over all losses over all (B,T) positions in the batch
1362	    // next: backward the classifier matmul
1363	    matmul_backward(grads_acts.bt4c, grads.wte, NULL, acts.output, acts.lnf, params.wte, B, T, C, Vp);
1364	    // backward the final layernorm
1365	    float* residual = acts.residual3 + (L-1) * B * T * C; // last residual is in residual3
1366	    float* dresidual = grads_acts.residual3; // the main buffer holding the gradient in the backward pass
1367	    layernorm_backward(dresidual, grads.lnfw, grads.lnfb, grads_acts.bt4c, residual, params.lnfw, acts.lnf_mean, acts.lnf_rstd, B, T, C);
1368	
1369	    // now backward all the layers
1370	    for (int l = L-1; l >= 0; l--) {
1371	        residual = l == 0 ? acts.encoded : acts.residual3 + (l-1) * B * T * C;
1372	
1373	        // get the pointers of the weights for this layer
1374	        float* l_ln1w = params.ln1w + l * C;
1375	        float* l_qkvw = params.qkvw + l * 3*C * C;
1376	        float* l_attprojw = params.attprojw + l * C * C;
1377	        float* l_ln2w = params.ln2w + l * C;
1378	        float* l_fcw = params.fcw + l * 4*C * C;
1379	        float* l_fcprojw = params.fcprojw + l * C * 4*C;
1380	        // get the pointers of the gradients of the weights for this layer
1381	        float* dl_ln1w = grads.ln1w + l * C;
1382	        float* dl_ln1b = grads.ln1b + l * C;
1383	        float* dl_qkvw = grads.qkvw + l * 3*C * C;
1384	        float* dl_qkvb = grads.qkvb + l * 3*C;
1385	        float* dl_attprojw = grads.attprojw + l * C * C;
1386	        float* dl_attprojb = grads.attprojb + l * C;
1387	        float* dl_ln2w = grads.ln2w + l * C;
1388	        float* dl_ln2b = grads.ln2b + l * C;
1389	        float* dl_fcw = grads.fcw + l * 4*C * C;
1390	        float* dl_fcb = grads.fcb + l * 4*C;
1391	        float* dl_fcprojw = grads.fcprojw + l * C * 4*C;
1392	        float* dl_fcprojb = grads.fcprojb + l * C;
1393	        // get the pointers of the activations for this layer
1394	        float* l_ln1 = acts.ln1 + l * B * T * C;
1395	        float* l_ln1_mean = acts.ln1_mean + l * B * T;
1396	        float* l_ln1_rstd = acts.ln1_rstd + l * B * T;
1397	        float* l_qkvr = acts.qkvr + l * B * T * 3*C;
1398	        float* l_atty = acts.atty + l * B * T * C;
1399	        float* l_att = acts.att + l * B * NH * T * T;
1400	        float* l_residual2 = acts.residual2 + l * B * T * C;
1401	        float* l_ln2 = acts.ln2 + l * B * T * C;
1402	        float* l_ln2_mean = acts.ln2_mean + l * B * T;
1403	        float* l_ln2_rstd = acts.ln2_rstd + l * B * T;
1404	        float* l_fch = acts.fch + l * B * T * 4*C;
1405	        float* l_fch_gelu = acts.fch_gelu + l * B * T * 4*C;
1406	        // get the pointers of the gradients of the activations for this layer
1407	        // notice that there is no l *, because we just have a single copy, and keep
1408	        // re-using this memory in every Transformer block as we calculate backward pass
1409	
1410	        // we need a B x T x C buffer; thankfully, the forward activation for lnf isn't needed anymore,
1411	        // so we can co-opt it here.
1412	        float* dl_btc = acts.lnf;
1413	        float* dl_bt4c = grads_acts.bt4c;
1414	        float* dl_preatt = grads_acts.preatt;
1415	
1416	        // re-use scratch buffer of the forward pass
1417	        float* scratch = acts.output;
1418	
1419	        // backprop this layer
1420	        matmul_backward(dl_bt4c, dl_fcprojw, dl_fcprojb, dresidual, l_fch_gelu, l_fcprojw, B, T, 4*C, C);
1421	        gelu_backward(dl_bt4c, l_fch, dl_bt4c, B*T*4*C);
1422	        matmul_backward(dl_btc, dl_fcw, dl_fcb, dl_bt4c, l_ln2, l_fcw, B, T, C, 4 * C);
1423	        // layernorm backward does += to the dresidual, so it correctly accumulates grad from the MLP block above
1424	        layernorm_backward(dresidual, dl_ln2w, dl_ln2b, dl_btc, l_residual2, l_ln2w, l_ln2_mean, l_ln2_rstd, B, T, C);
1425	        matmul_backward(dl_btc, dl_attprojw, dl_attprojb, dresidual, l_atty, l_attprojw, B, T, C, C);
1426	        // we more B x T x (4)C buffers. l_atty and l_fch aren't needed anymore at this point, so reuse their memory
1427	        float* buffer_a = l_atty;
1428	        float* buffer_b = l_fch;        // this is B x T x 4C, so even larger than what we need
1429	
1430	        attention_backward(dl_bt4c, buffer_b, dl_preatt, scratch, buffer_a, dl_btc, l_qkvr, l_att, B, T, C, NH);
1431	        matmul_backward(dl_btc, dl_qkvw, dl_qkvb, dl_bt4c, l_ln1, l_qkvw, B, T, C, 3 * C);
1432	        // layernorm backward does += to dresidual, so it correctly accumulates gradient for the Attention block above
1433	        layernorm_backward(dresidual, dl_ln1w, dl_ln1b, dl_btc, residual, l_ln1w, l_ln1_mean, l_ln1_rstd, B, T, C);
1434	    }
1435	    encoder_backward(grads.wte, grads.wpe, dresidual, model->inputs, B, T, C);
1436	}
