1438	void gpt2_update(GPT2 *model, float learning_rate, float beta1, float beta2, float eps, float weight_decay, int t) {
1439	    // reference: https://pytorch.org/docs/stable/generated/torch.optim.AdamW.html
1440	
1441	    // lazily allocate the memory for m_memory and v_memory
1442	    if (model->m_memory == NULL) {
1443	        cudaCheck(cudaMalloc((void**)&model->m_memory, model->num_parameters * sizeof(float)));
1444	        cudaCheck(cudaMalloc((void**)&model->v_memory, model->num_parameters * sizeof(float)));
1445	        cudaCheck(cudaMemset(model->m_memory, 0, model->num_parameters * sizeof(float)));
1446	        cudaCheck(cudaMemset(model->v_memory, 0, model->num_parameters * sizeof(float)));
1447	        printf("allocated %zu MiB for AdamW optimizer state m\n", (model->num_parameters * sizeof(float)) >> 20);
1448	        printf("allocated %zu MiB for AdamW optimizer state v\n", (model->num_parameters * sizeof(float)) >> 20);
1449	    }
1450	
1451	    int block_size = 512;
1452	    int num_blocks = CEIL_DIV(model->num_parameters, block_size);
1453	    float beta1_correction = 1.0f - powf(beta1, t);
1454	    float beta2_correction = 1.0f - powf(beta2, t);
1455	    adamw_kernel2<<<num_blocks, block_size>>>(model->params_memory, model->grads_memory, model->m_memory, model->v_memory,
1456	                                              model->num_parameters,
1457	                                              learning_rate, beta1, beta2, beta1_correction, beta2_correction, eps, weight_decay);
1458	    cudaCheck(cudaGetLastError());
1459	}
