1464	    cudaCheck(cudaFree(model->m_memory));
1465	    cudaCheck(cudaFree(model->v_memory));
1466	    cudaCheck(cudaFree(model->acts_memory));
1467	    cudaCheck(cudaFree(model->grads_acts_memory));
1468	    cudaCheck(cudaFree(model->inputs));
1469	    cudaCheck(cudaFree(model->targets));
1470	    cudaFreeHost(model->cpu_losses);
1471	}
