1476	// sampler: takes probabilities and samples integers from them
1477	
1478	#define GPT2_EOT 50256
1479	
1480	unsigned int random_u32(unsigned long long *state) {
1481	    // xorshift rng: https://en.wikipedia.org/wiki/Xorshift#xorshift.2A
1482	    *state ^= *state >> 12;
1483	    *state ^= *state << 25;
1484	    *state ^= *state >> 27;
1485	    return (*state * 0x2545F4914F6CDD1Dull) >> 32;
1486	}
1487	float random_f32(unsigned long long *state) { // random float32 in [0,1)
1488	    return (random_u32(state) >> 8) / 16777216.0f;
1489	}
1490	
1491	int sample_softmax(const float* logits, int n, float coin) {
1492	    // sample index from logits (converted to probabilities using softmax)
1493	    // coin is a random number in [0, 1), usually from random_f32()
1494	    double norm = 0;
1495	    for (int i = 0; i < n; i++) {
1496	        norm += expf(logits[i]);
1497	    }
1498	    // instead of dividing all exp(logits), we can just multiply coin.
1499	    coin *= norm;
1500	    float cdf = 0.0f;
1501	    for (int i = 0; i < n; i++) {
1502	        cdf += expf(logits[i]);
1503	        if (coin < cdf) {
1504	            return i;
1505	        }
1506	    }
1507	    return n - 1; // in case of rounding errors
1508	}
