1561	// main training loop
1562	int main(int argc, char *argv[]) {
1563	
1564	    // read in the (optional) command line arguments
1565	    const char* train_data_pattern = "dev/data/tinyshakespeare/tiny_shakespeare_train.bin";
1566	    const char* val_data_pattern = "dev/data/tinyshakespeare/tiny_shakespeare_val.bin";
1567	    const char* output_log_file = NULL;
1568	    int B = 4; // batch size
1569	    int T = 1024; // sequence length max
1570	    float learning_rate = 3e-4f;
1571	    int val_loss_every = 20; // every how many steps do we eval validation loss?
1572	    int val_max_steps = 20; // how many batches max do we eval for validation loss?
1573	    int sample_every = 20; // every how many steps to do inference?
1574	    int genT = 64; // number of steps of inference we will do
1575	    for (int i = 1; i < argc; i+=2) {
1576	        if (i + 1 >= argc) { error_usage(); } // must have arg after flag
1577	        if (argv[i][0] != '-') { error_usage(); } // must start with dash
1578	        if (strlen(argv[i]) != 2) { error_usage(); } // must be -x (one dash, one letter)
1579	        // read in the args
1580	        if (argv[i][1] == 'i') { train_data_pattern = argv[i+1]; }
1581	        else if (argv[i][1] == 'j') { val_data_pattern = argv[i+1]; }
1582	        else if (argv[i][1] == 'o') { output_log_file = argv[i+1]; }
1583	        else if (argv[i][1] == 'b') { B = atoi(argv[i+1]); }
1584	        else if (argv[i][1] == 't') { T = atoi(argv[i+1]); }
1585	        else if (argv[i][1] == 'l') { learning_rate = atof(argv[i+1]); }
1586	        else if (argv[i][1] == 'v') { val_loss_every = atoi(argv[i+1]); }
1587	        else if (argv[i][1] == 'm') { val_max_steps = atoi(argv[i+1]); }
1588	        else if (argv[i][1] == 's') { sample_every = atoi(argv[i+1]); }
1589	        else if (argv[i][1] == 'g') { genT = atoi(argv[i+1]); }
1590	        else { error_usage(); }
1591	    }
1592	    printf("+-----------------------+----------------------------------------------------+\n");
1593	    printf("| Parameter             | Value                                              |\n");
1594	    printf("+-----------------------+----------------------------------------------------+\n");
1595	    printf("| train data pattern    | %-50s |\n", train_data_pattern);
1596	    printf("| val data pattern      | %-50s |\n", val_data_pattern);
1597	    printf("| output log file       | %-50s |\n", output_log_file == NULL ? "NULL" : output_log_file);
1598	    printf("| batch size B          | %-50d |\n", B);
1599	    printf("| sequence length T     | %-50d |\n", T);
1600	    printf("| learning rate         | %-50f |\n", learning_rate);
1601	    printf("| val_loss_every        | %-50d |\n", val_loss_every);
1602	    printf("| val_max_steps         | %-50d |\n", val_max_steps);
1603	    printf("| sample_every          | %-50d |\n", sample_every);
1604	    printf("| genT                  | %-50d |\n", genT);
1605	    printf("+-----------------------+----------------------------------------------------+\n");
1606	
1607	    // set up the device
1608	    int deviceIdx = 0;
1609	    cudaCheck(cudaSetDevice(deviceIdx));
1610	    cudaDeviceProp deviceProp;
1611	    cudaGetDeviceProperties(&deviceProp, deviceIdx);
1612	    // setup cuBLAS and cuBLASLt
1613	    cublasCheck(cublasCreate(&cublas_handle));
1614	    // TF32 precision is equivalent to torch.set_float32_matmul_precision('high')
1615	    int enable_tf32 = deviceProp.major >= 8 ? 1 : 0;
1616	    cublas_compute_type = enable_tf32 ? CUBLAS_COMPUTE_32F_FAST_TF32 : CUBLAS_COMPUTE_32F;
1617	    cublasMath_t cublas_math_mode = enable_tf32 ? CUBLAS_TF32_TENSOR_OP_MATH : CUBLAS_DEFAULT_MATH;
1618	    cublasCheck(cublasSetMathMode(cublas_handle, cublas_math_mode));
1619	    printf("| device                | %-50s |\n", deviceProp.name);
1620	    printf("| TF32                  | %-50s |\n", enable_tf32 ? "enabled" : "disabled");
1621	    printf("+-----------------------+----------------------------------------------------+\n");
1622	
1623	    // build the GPT-2 model from a checkpoint
1624	    GPT2 model;
1625	    gpt2_build_from_checkpoint(&model, "gpt2_124M.bin");
1626	    printf("| max_sequence_length T | %-50d |\n", model.config.max_seq_len);
1627	    printf("| vocab_size V          | %-50d |\n", model.config.vocab_size);
1628	    printf("| padded_vocab_size Vp  | %-50d |\n", model.config.padded_vocab_size);
1629	    printf("| num_layers L          | %-50d |\n", model.config.num_layers);
1630	    printf("| num_heads NH          | %-50d |\n", model.config.num_heads);
1631	    printf("| channels C            | %-50d |\n", model.config.channels);
1632	    printf("| num_parameters        | %-50zu |\n", model.num_parameters);
1633	    printf("+-----------------------+----------------------------------------------------+\n");
1634	
1635	    // build DataLoaders for both train and val
1636	    DataLoader train_loader, val_loader;
1637	    dataloader_init(&train_loader, train_data_pattern, B, T, 0, 1, 1);
1638	    dataloader_init(&val_loader, val_data_pattern, B, T, 0, 1, 0);
1639	    int train_num_batches = train_loader.num_tokens / (B*T); // let's do 1 epoch by default for now
1640	    int val_num_batches = val_loader.num_tokens / (B*T);
1641	    if (val_num_batches > val_max_steps) { val_num_batches = val_max_steps; }
1642	    printf("| train_num_batches     | %-50d |\n", train_num_batches);
1643	    printf("| val_num_batches       | %-50d |\n", val_num_batches);
1644	    printf("+-----------------------+----------------------------------------------------+\n");
1645	
1646	    // print model parameter allocations from gpt2_build_from_checkpoint down here to not mess up our table above
1647	    printf("allocated %d MiB for model parameters\n", (int)round(model.num_parameters * sizeof(float) / (1024 * 1024)));
1648	
1649	    // set up the Logger
1650	    Logger logger;
1651	    logger_init(&logger, output_log_file);
1652	
1653	    // build the Tokenizer
1654	    Tokenizer tokenizer;
1655	    tokenizer_init(&tokenizer, "gpt2_tokenizer.bin");
1656	
1657	    // some memory for generating samples from the model
1658	    unsigned long long rng_state = 1337;
1659	    int* gen_tokens = (int*)mallocCheck(B * T * sizeof(int));
1660	    float* cpu_logits = (float*)mallocCheck(model.config.vocab_size * sizeof(float));
1661	
1662	    // train
1663	    struct timespec start, end;
1664	    double total_sum_iteration_time_s = 0.0;
1665	    for (int step = 0; step <= train_num_batches; step++) {
1666	        int last_step = step == train_num_batches;
1667	
1668	        // once in a while estimate the validation loss
1669	        if (step % val_loss_every == 0 || last_step) {
1670	            float val_loss = 0.0f;
1671	            dataloader_reset(&val_loader);
1672	            for (int i = 0; i < val_num_batches; i++) {
1673	                dataloader_next_batch(&val_loader);
1674	                gpt2_forward(&model, val_loader.inputs, val_loader.targets, B, T);
1675	                val_loss += model.mean_loss;
1676	            }
1677	            val_loss /= val_num_batches;
1678	            printf("val loss %f\n", val_loss);
1679	            logger_log_val(&logger, step, val_loss);
1680	        }
1681	
1682	        // once in a while do model inference to print generated text
1683	        if (step > 0 && step % sample_every == 0 || last_step) {
1684	            // fill up gen_tokens with the GPT2_EOT, which kicks off the generation
1685	            for(int i = 0; i < B * T; ++i) {
1686	                gen_tokens[i] = GPT2_EOT;
1687	            }
1688	            // now sample from the model autoregressively
1689	            printf("generating:\n---\n");
1690	            for (int t = 1; t < genT; t++) {
1691	                // note that inference is very wasteful here because for each token
1692	                // we re-calculate the forward pass for all of (B,T) positions from scratch
1693	                // but the inference here is just for sanity checking anyway
1694	                // and we can maybe optimize a bit more later, with careful tests
1695	                gpt2_forward(&model, gen_tokens, NULL, B, T);
1696	                // furthermore, below we're only using b=0 (i.e. the first row) of all B rows
1697	                // we're in principle running B "inference streams" in parallel here
1698	                // only using position 0 because it's a bit faster (copy less probs from GPU -> CPU)
1699	                // get the V-dimensional vector probs[0, t-1, :]
1700	                float* logits = model.acts.output + (t - 1) * model.config.padded_vocab_size;
1701	                // move probs back to CPU and sample (note we only move the first vocab_size logits, ignoring the padding)
1702	                cudaCheck(cudaMemcpy(cpu_logits, logits, model.config.vocab_size * sizeof(float), cudaMemcpyDeviceToHost));
1703	                float coin = random_f32(&rng_state);
1704	                int next_token = sample_softmax(cpu_logits, model.config.vocab_size, coin);
1705	                gen_tokens[t] = next_token;
1706	                // print the generated token, either using the Tokenizer or a fallback
1707	                if (tokenizer.init_ok) {
1708	                    const char* token_str = tokenizer_decode(&tokenizer, next_token);
1709	                    safe_printf(token_str);
1710	                } else {
1711	                    // fall back to printing the token id
1712	                    printf("%d ", next_token);
1713	                }
1714	                fflush(stdout);
1715	            }
1716	            printf("\n---\n");
1717	        }
1718	
1719	        // bit confusing: we want to make sure to eval and sample on 0th iteration
1720	        // but also after the very last iteration. so we loop for step <= train_num_batches
1721	        // instead of just < train_num_batches (one extra due to <=), only to do
1722	        // the validation/sampling one last time, and then we break right here as we're done.
1723	        if (last_step) { break; }
1724	
1725	        // do a training step
1726	        clock_gettime(CLOCK_MONOTONIC, &start);
1727	        dataloader_next_batch(&train_loader);
1728	        gpt2_forward(&model, train_loader.inputs, train_loader.targets, B, T);
1729	        gpt2_zero_grad(&model);
1730	        gpt2_backward(&model);
1731	        gpt2_update(&model, learning_rate, 0.9f, 0.999f, 1e-8f, 0.0f, step+1);
1732	        cudaCheck(cudaDeviceSynchronize()); // finish all CUDA work to get correct precise timings
1733	        clock_gettime(CLOCK_MONOTONIC, &end);
1734	        double time_elapsed_s = (end.tv_sec - start.tv_sec) + (end.tv_nsec - start.tv_nsec) / 1e9;
1735	        total_sum_iteration_time_s += time_elapsed_s;
1736	        int tokens_per_second = (B * T) / time_elapsed_s;
1737	        printf("step %4d/%d: train loss %f (%f ms, %d tok/s)\n", step + 1, train_num_batches, model.mean_loss, time_elapsed_s * 1000, tokens_per_second);
1738	        logger_log_train(&logger, step, model.mean_loss);
1739	    }
1740	    // add a total average, for optimizations that are only mild improvements
1741	    printf("total average iteration time: %f ms\n", total_sum_iteration_time_s / train_num_batches * 1000);
1742	
1743	    // free
1744	    dataloader_free(&train_loader);
1745	    dataloader_free(&val_loader);
1746	    tokenizer_free(&tokenizer);
1747	    gpt2_free(&model);
1748	    free(cpu_logits);
